## Task: Implement Hermes-Inspired MemoryProvider for SportsBettingSwarm

Context: The SportsBettingSwarm at `<workspace>/SportsBettingSwarm/` loses cross-round learning because workers read the entire `docs/problem.md` (flat append-only text, grows unbounded). NousResearch Hermes Agent v0.8.0 solves this with a SQLite SessionDB + FTS5 that injects a frozen semantic snapshot at session start. We want to port this pattern.

### Step 1: Clone Hermes for reference
```bash
git clone --depth 1 --branch v0.8.0 https://github.com/NousResearch/hermes-agent <workspace>/Tools/hermes-agent-audit
```
Read `agent/memory_provider.py` and `SessionDB` to confirm the FTS5 schema before implementing.

### Step 2: Create `orchestrator/memory_store.js`
Path: `<workspace>/SportsBettingSwarm/orchestrator/memory_store.js`

Use `better-sqlite3` (check if already in package.json; if not, add it). Implement:

```javascript
const Database = require('better-sqlite3');
const path = require('path');

const DB_PATH = path.join(__dirname, '../data/swarm_memory.db');

function initDB() {
  const db = new Database(DB_PATH);
  db.pragma('journal_mode = WAL');
  db.exec(`
    CREATE TABLE IF NOT EXISTS rounds (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      round_num INTEGER,
      agent_id TEXT,
      strategy_name TEXT,
      score REAL,
      roi REAL,
      win_rate REAL,
      hypothesis TEXT,
      insight TEXT,
      timestamp TEXT DEFAULT (datetime('now'))
    );
    CREATE VIRTUAL TABLE IF NOT EXISTS rounds_fts
    USING fts5(hypothesis, insight, content='rounds', content_rowid='id');
    CREATE TRIGGER IF NOT EXISTS rounds_ai AFTER INSERT ON rounds BEGIN
      INSERT INTO rounds_fts(rowid, hypothesis, insight) VALUES (new.id, new.hypothesis, new.insight);
    END;
  `);
  return db;
}

function storeRound({ roundNum, agentId, strategyName, score, roi, winRate, hypothesis, insight }) {
  const db = initDB();
  db.prepare(`INSERT INTO rounds (round_num, agent_id, strategy_name, score, roi, win_rate, hypothesis, insight)
    VALUES (?, ?, ?, ?, ?, ?, ?, ?)`)
    .run(roundNum, agentId, strategyName, score, roi, winRate, hypothesis, insight);
  db.close();
}

function queryRelevant(keywords, limit = 10) {
  const db = initDB();
  const rows = db.prepare(`
    SELECT r.round_num, r.agent_id, r.strategy_name, r.score, r.roi, r.win_rate, r.hypothesis, r.insight
    FROM rounds_fts f JOIN rounds r ON f.rowid = r.id
    WHERE rounds_fts MATCH ?
    ORDER BY r.score DESC LIMIT ?`).all(keywords, limit);
  db.close();
  return rows;
}

function getRecentRounds(n = 5) {
  const db = initDB();
  const rows = db.prepare(`SELECT * FROM rounds ORDER BY round_num DESC, score DESC LIMIT ?`).all(n);
  db.close();
  return rows;
}

function generateSessionContext(hypothesis) {
  let rows = queryRelevant(hypothesis);
  if (rows.length === 0) rows = getRecentRounds(5);
  if (rows.length === 0) return '';
  const lines = rows.map(r =>
    `[Round ${r.round_num}] ${r.strategy_name} | Score: ${r.score?.toFixed(3)} | ROI: ${r.roi?.toFixed(3)} | WinRate: ${r.win_rate?.toFixed(3)}\nHypothesis: ${r.hypothesis}\nInsight: ${r.insight}`
  );
  return `## Relevant Past Learnings (injected)\n${lines.join('\n---\n')}`;
}

module.exports = { initDB, storeRound, queryRelevant, getRecentRounds, generateSessionContext };
```

